  1→/**
  2→ * Seed script для начального наполнения БД.
  3→ * Запуск: npm run db:seed (или: cd apps/web && tsx prisma/seed.ts)
  4→ *
  5→ * Создаёт:
  6→ * - 5 ролей (owner, sales, manager, accountant, storekeeper)
  7→ * - 1 пользователя-owner (для первого входа)
  8→ * - Справочник источников лидов
  9→ * - 1 воронку со стадиями (для модуля Сделки)
 10→ * - Корневые категории (для модуля Финансы)
 11→ */
 12→import { PrismaClient } from '@prisma/client';
 13→import * as bcrypt from 'bcryptjs';
 14→
 15→const prisma = new PrismaClient();
 16→
 17→async function main() {
 18→  console.log('🌱 Seeding...');
 19→
 20→  // === Роли ===
 21→  const roles = [
 22→    {
 23→      code: 'owner',
 24→      name: 'Владелец',
 25→      description: 'Полный доступ ко всему',
 26→      permissions: ['*'],
 27→    },
 28→    {
 29→      code: 'sales',
 30→      name: 'Менеджер по продажам',
 31→      description: 'Работает с контактами и сделками',
 32→      permissions: ['contact:*', 'deal:*', 'interaction:*'],
 33→    },
 34→    {
 35→      code: 'manager',
 36→      name: 'Менеджер проектов',
 37→      description: 'Ведёт проекты и закупки',
 38→      permissions: ['project:*', 'bom:*', 'purchase:*', 'invoice:*', 'warehouse:read'],
 39→    },
 40→    {
 41→      code: 'accountant',
 42→      name: 'Бухгалтер',
 43→      description: 'Финансы, импорт выписок',
 44→      permissions: ['transaction:*', 'budget:*', 'invoice:*', 'report:*'],
 45→    },
 46→    {
 47→      code: 'storekeeper',
 48→      name: 'Кладовщик',
 49→      description: 'Склад, приёмка, списание',
 50→      permissions: ['warehouse:*', 'delivery:*'],
 51→    },
 52→  ];
 53→
 54→  for (const role of roles) {
 55→    await prisma.role.upsert({
 56→      where: { code: role.code },
 57→      update: role,
 58→      create: role,
 59→    });
 60→    console.log(`  ✓ Role: ${role.code}`);
 61→  }
 62→
 63→  // === Owner пользователь ===
 64→  const passwordHash = await bcrypt.hash('admin123', 12);
 65→  const owner = await prisma.user.upsert({
 66→    where: { email: 'admin@local' },
 67→    update: {},
 68→    create: {
 69→      email: 'admin@local',
 70→      name: 'Администратор',
 71→      passwordHash,
 72→      isActive: true,
 73→    },
 74→  });
 75→  const ownerRole = await prisma.role.findUnique({ where: { code: 'owner' } });
 76→  if (ownerRole) {
 77→    await prisma.userRole.upsert({
 78→      where: { userId_roleId: { userId: owner.id, roleId: ownerRole.id } },
 79→      update: {},
 80→      create: { userId: owner.id, roleId: ownerRole.id },
 81→    });
 82→  }
 83→  console.log('  ✓ Owner user: admin@local / admin123');
 84→
 85→  // === Источники лидов ===
 86→  const sources = [
 87→    { code: 'call', name: 'Звонок', description: 'Входящий звонок' },
 88→    { code: 'office', name: 'Визит в офис', description: 'Личный визит' },
 89→    { code: 'website', name: 'Сайт', description: 'Заявка с сайта' },
 90→    { code: 'email', name: 'Email', description: 'Обращение по email' },
 91→    { code: 'telegram', name: 'Telegram', description: 'Обращение в Telegram' },
 92→    { code: 'referral', name: 'Рекомендация', description: 'Пришёл по рекомендации' },
 93→    { code: 'other', name: 'Другое', description: 'Прочее' },
 94→  ];
 95→  for (const s of sources) {
 96→    await prisma.leadSource.upsert({
 97→      where: { code: s.code },
 98→      update: s,
 99→      create: s,
100→    });
101→  }
102→  console.log(`  ✓ Lead sources: ${sources.length}`);
103→
104→  // === Воронка по умолчанию ===
105→  const pipeline = await prisma.pipeline.upsert({
106→    where: { code: 'default' },
107→    update: {},
108→    create: {
109→      code: 'default',
110→      name: 'Воронка по умолчанию',
111→      description: 'Стандартная воронка B2B-продаж',
112→      isActive: true,
113→    },
114→  });
115→
116→  const stages = [
117→    { code: 'new', name: 'Новый лид', order: 1, probability: 0.1, color: '#94a3b8' },
118→    { code: 'qualified', name: 'Квалификация', order: 2, probability: 0.25, color: '#3b82f6' },
119→    { code: 'meeting', name: 'Встреча', order: 3, probability: 0.4, color: '#8b5cf6' },
120→    { code: 'proposal', name: 'КП', order: 4, probability: 0.55, color: '#ec4899' },
121→    { code: 'negotiation', name: 'Переговоры', order: 5, probability: 0.7, color: '#f59e0b' },
122→    { code: 'contract', name: 'Договор', order: 6, probability: 0.9, color: '#10b981' },
123→    { code: 'won', name: 'Выиграно', order: 7, probability: 1.0, isWonStage: true, color: '#059669' },
124→    { code: 'lost', name: 'Потеряно', order: 8, probability: 0, isLostStage: true, color: '#ef4444' },
125→  ];
126→  for (const s of stages) {
127→    await prisma.dealStage.upsert({
128→      where: { pipelineId_code: { pipelineId: pipeline.id, code: s.code } },
129→      update: s,
130→      create: { ...s, pipelineId: pipeline.id },
131→    });
132→  }
133→  console.log(`  ✓ Default pipeline with ${stages.length} stages`);
134→
135→  // === Категории финансов ===
136→  const categories = [
137→    { name: 'Выручка', type: 'income', order: 1 },
138→    { name: 'Материалы', type: 'expense', order: 1 },
139→    { name: 'Подрядчики', type: 'expense', order: 2 },
140→    { name: 'Зарплаты', type: 'expense', order: 3 },
141→    { name: 'Аренда', type: 'expense', order: 4 },
142→    { name: 'Налоги', type: 'expense', order: 5 },
143→    { name: 'Транспорт', type: 'expense', order: 6 },
144→    { name: 'Прочее', type: 'expense', order: 99 },
145→  ];
146→  for (const c of categories) {
147→    await prisma.category.create({ data: c }).catch(() => {
148→      // ignore duplicates
149→    });
150→  }
151→  console.log(`  ✓ Categories: ${categories.length}`);
152→
153→  console.log('✅ Seeding complete');
154→  console.log('');
155→  console.log('Login: admin@local / admin123');
156→}
157→
158→main()
159→  .catch((e) => {
160→    console.error('❌ Seed failed:', e);
161→    process.exit(1);
162→  })
163→  .finally(async () => {
164→    await prisma.$disconnect();
165→  });
